-- Troubleshoot articles (English)
INSERT INTO kb_articles (title, content, category, language, is_published, is_internal, tags) VALUES
('My eSIM is not activating', 'Steps to troubleshoot when your eSIM won''t activate. Check device compatibility - make sure your device supports eSIM and is carrier unlocked. Check your internet connection - eSIM activation requires stable Wi-Fi or mobile data. Restart your device - turn off completely, wait 30 seconds, turn back on. Contact support if issues persist with order number and device model.', 'troubleshoot', 'en', true, false, ARRAY['activation', 'not working', 'troubleshoot']),
('I have no internet connection', 'What to do when your eSIM has no data connection. Enable data roaming in Settings > Cellular. Select eSIM for data in cellular settings. Check network coverage in your area. Try manual network selection if automatic doesn''t work.', 'troubleshoot', 'en', true, false, ARRAY['no internet', 'connection', 'data roaming']),
('My internet speed is slow', 'Tips to improve your eSIM data speed. Check your data limit in account dashboard. Network congestion varies by time and location. Select preferred network type (5G/LTE) in settings for faster speeds.', 'troubleshoot', 'en', true, false, ARRAY['slow speed', 'internet speed', 'network']),
('I cannot scan the QR code', 'What to do if you have trouble scanning your eSIM QR code. Display QR on another device. Ensure good lighting. Try manual installation with SM-DP+ address and activation code from email.', 'troubleshoot', 'en', true, false, ARRAY['QR code', 'scan', 'installation']),
('eSIM Stuck at Activating', 'What to do when your eSIM is stuck in activating status. Normally takes 1-5 minutes. Check internet connection. Restart device. Check cellular settings. Contact support if stuck more than 30 minutes.', 'troubleshoot', 'en', true, false, ARRAY['stuck', 'activating', 'pending']),
('Cellular Plans Cannot Be Added Error', 'How to fix the "Cellular Plans from This Carrier Cannot Be Added" error. Check if device is carrier-locked. Verify QR code hasn''t been used. Update software. Try manual installation.', 'troubleshoot', 'en', true, false, ARRAY['error', 'cannot add', 'carrier locked']),
('What are the APN Settings for my eSIM?', 'Understanding and configuring APN settings. Most Mobile11 eSIMs configure APN automatically. If needed, enter APN settings from order email manually in cellular settings.', 'troubleshoot', 'en', true, false, ARRAY['APN', 'settings', 'configuration']),
('This Code Is No Longer Valid Error', 'What to do when you see the code is no longer valid message. QR code may already be used (each works once). Check if eSIM is already installed. Contact support for replacement if deleted.', 'troubleshoot', 'en', true, false, ARRAY['invalid code', 'QR code', 'error']),
('eSIM Not Showing in Settings', 'Troubleshoot when eSIM doesn''t appear in device settings. Check if installation completed. Restart device. Go to Settings > Cellular to find eSIM profile.', 'troubleshoot', 'en', true, false, ARRAY['not showing', 'settings', 'missing']),
('Data Not Working After Landing', 'Fix data issues when arriving at destination. Enable data roaming. Select eSIM for mobile data. Wait 5-10 minutes for network registration. Try manual network selection.', 'troubleshoot', 'en', true, false, ARRAY['landing', 'arrival', 'data not working']),
('How to Delete eSIM from Device', 'Steps to remove eSIM profile from your device. iPhone: Settings > Cellular > tap eSIM > Remove Cellular Plan. Android: Settings > Connections > SIM Manager > delete profile. Warning: deleted eSIM cannot be reinstalled with same QR code.', 'troubleshoot', 'en', true, false, ARRAY['delete', 'remove', 'uninstall']),
('eSIM Working but No Signal Bars', 'Troubleshoot when eSIM is active but shows no signal. This may be normal if using eSIM only for data. Check data connection works. Try different network.', 'troubleshoot', 'en', true, false, ARRAY['no signal', 'signal bars', 'connection']),
('Cannot Make Calls with eSIM', 'Mobile11 eSIMs are data-only. They do not support voice calls or SMS. Keep your regular SIM for calls. Use WhatsApp, LINE, or other VoIP apps for calls over data.', 'troubleshoot', 'en', true, false, ARRAY['calls', 'voice', 'SMS', 'data only']),
('eSIM Data Depleted Before Expected', 'Track your data usage in account dashboard. Check for background app updates. Some apps consume data quickly (video streaming, cloud backups). Consider top-up or larger plan.', 'troubleshoot', 'en', true, false, ARRAY['data usage', 'depleted', 'running out']),

-- eSIM Data Plan articles (English)
('How to Top Up Your eSIM', 'Learn how to add more data to your existing eSIM. Top-up allows adding data without reinstalling. Log into account, go to My eSIMs, select eSIM, click Top Up. Data added automatically within 5-15 minutes.', 'esim-data-plan', 'en', true, false, ARRAY['top up', 'add data', 'reload']),
('Understanding Mobile11 Plan Types', 'Learn about Day Pass, Max Speed, and Limitless plans. All plans are truly unlimited - you are never cut off. Day Pass: daily high-speed allowance resets every 24 hours, then 1 Mbps fallback. Max Speed: bulk high-speed data upfront, then 384 Kbps fallback. Limitless: unlimited data at maximum speeds with no throttling.', 'esim-data-plan', 'en', true, false, ARRAY['plan types', 'day pass', 'max speed', 'limitless', 'unlimited']),
('Regional vs Local eSIM', 'Compare regional and local eSIM options. Local eSIM: best value per GB, optimal for single country. Regional eSIM: one eSIM for multiple countries, convenient for multi-destination trips.', 'esim-data-plan', 'en', true, false, ARRAY['regional', 'local', 'multi-country']),
('When Does My eSIM Validity Start?', 'Validity starts when you first connect to a network at your destination, not when you install. Install before travel, activate when you arrive. Check specific plan terms for details.', 'esim-data-plan', 'en', true, false, ARRAY['validity', 'start date', 'expiry']),
('How to Check Data Usage', 'Check your data usage in the Mobile11 account dashboard under My eSIMs. Also check in device settings: iPhone Settings > Cellular, Android Settings > Data Usage.', 'esim-data-plan', 'en', true, false, ARRAY['data usage', 'check balance', 'remaining data']),
('Can I Use eSIM as Hotspot?', 'Yes, most Mobile11 eSIMs support hotspot/tethering. Enable in Settings > Personal Hotspot (iPhone) or Settings > Hotspot (Android). Note: hotspot uses data faster.', 'esim-data-plan', 'en', true, false, ARRAY['hotspot', 'tethering', 'share data']),
('eSIM Coverage and Networks', 'Mobile11 works in 150+ countries. Each plan lists covered countries and partner networks. Best coverage with local carrier partners for each destination.', 'esim-data-plan', 'en', true, false, ARRAY['coverage', 'networks', 'countries']),
('What Speed Can I Expect?', 'Speeds depend on plan type and local network. Limitless: maximum network speed (LTE/5G). Day Pass after limit: 1 Mbps. Max Speed after limit: 384 Kbps. Actual speeds vary by location and congestion.', 'esim-data-plan', 'en', true, false, ARRAY['speed', 'LTE', '5G', 'network speed']),
('Extending Your eSIM Plan', 'Extend validity or add data by purchasing a top-up. Log into account, select your eSIM, choose add-on package. Some plans support extension, others require new purchase.', 'esim-data-plan', 'en', true, false, ARRAY['extend', 'renewal', 'add time']),

-- Payments and Billing articles (English)
('Payment Methods Accepted', 'Mobile11 accepts credit cards (Visa, Mastercard, Amex), debit cards, PayPal, Google Pay, Apple Pay, and local payment methods including PromptPay in Thailand.', 'payments-billing', 'en', true, false, ARRAY['payment methods', 'credit card', 'PayPal']),
('Refund Policy', 'Refunds available within 30 days if eSIM has not been installed/activated. Once QR code is scanned, the eSIM cannot be refunded. Contact support for refund requests with order number.', 'payments-billing', 'en', true, false, ARRAY['refund', 'return', 'money back']),
('How to Get Invoice', 'Access invoices in your account dashboard under Order History. Click on any order to view and download PDF invoice. For additional billing needs, contact support.', 'payments-billing', 'en', true, false, ARRAY['invoice', 'receipt', 'billing']),
('Currency and Pricing', 'Prices shown in USD by default. Currency can be changed to THB and others. Final charge in your local currency depends on your card issuer''s exchange rate.', 'payments-billing', 'en', true, false, ARRAY['currency', 'pricing', 'exchange rate']),
('Payment Failed', 'If payment fails, check card details, ensure sufficient funds, try different payment method. Contact your bank if card is declined. Try again or use alternative payment.', 'payments-billing', 'en', true, false, ARRAY['payment failed', 'declined', 'error']),
('Promo Codes and Discounts', 'Enter promo code at checkout in the discount field. Promo codes cannot be combined with referral discounts. Each promo code has specific terms and validity period.', 'payments-billing', 'en', true, false, ARRAY['promo code', 'discount', 'coupon']),

-- Account articles (English)
('How to Create Account', 'Create account on Mobile11 website or app. Enter email and password, or sign up with Google/LINE. Verify email to complete registration. Account required for loyalty program and order management.', 'account', 'en', true, false, ARRAY['create account', 'sign up', 'register']),
('Forgot Password', 'Reset password via login page. Click "Forgot Password", enter email, check inbox for reset link. Link valid for 24 hours. Contact support if issues persist.', 'account', 'en', true, false, ARRAY['forgot password', 'reset', 'login']),
('Update Account Information', 'Update profile in account settings. Change name, email, phone number. For email change, verification required for new email address.', 'account', 'en', true, false, ARRAY['update account', 'profile', 'settings']),
('What is Mobile11 Money?', 'Mobile11 Money is our cashback reward currency. Earn 5-15% back on purchases based on loyalty tier. Use at checkout to reduce order total. 1 Mobile11 Money = $1 USD. Valid for 1 year (resets with each purchase).', 'account', 'en', true, false, ARRAY['mobile11 money', 'cashback', 'rewards']),
('Mobile11 Loyalty Program', 'Three-tier loyalty program: Explorer (5% cashback), Silver Explorer (10% at $100 spent), Gold Explorer (15% at $500 spent). Automatic enrollment with first purchase. Tiers never expire.', 'account', 'en', true, false, ARRAY['loyalty', 'tiers', 'cashback', 'rewards']),
('How to Use Mobile11 Money', 'Apply Mobile11 Money at checkout. Enter amount to use or click "Use All". Remaining balance shown in account. Can combine with regular payment but not with promo codes.', 'account', 'en', true, false, ARRAY['use rewards', 'redeem', 'checkout']),
('Referral Program', 'Refer friends and earn $5.00 Mobile11 Money when they make their first qualifying purchase (minimum $10 order). Share your unique referral link from account dashboard. Friends also get a $5.00 welcome discount.', 'account', 'en', true, false, ARRAY['referral', 'invite friends', 'earn rewards']),
('View Order History', 'Access order history in account dashboard. See all past orders, download eSIM QR codes, check order status, and access invoices.', 'account', 'en', true, false, ARRAY['order history', 'past orders', 'purchases']),
('Account Security', 'Keep account secure with strong password. Enable two-factor authentication if available. Never share login credentials. Report suspicious activity to support.', 'account', 'en', true, false, ARRAY['security', 'password', 'protection']),

-- About eSIM / FAQ articles (English)
('What is an eSIM?', 'An eSIM (embedded SIM) is a digital SIM that allows you to activate a cellular plan without using a physical SIM card. It''s built into your device and can be programmed with carrier information remotely. Key benefits: instant activation, no physical SIM to lose, can store multiple profiles, environmentally friendly.', 'faq', 'en', true, false, ARRAY['what is esim', 'definition', 'digital SIM']),
('Is my phone eSIM compatible?', 'Most modern smartphones support eSIM. Compatible iPhones: XS, XR and later, SE 2nd gen and later. Compatible Android: Samsung Galaxy S20+, Google Pixel 3+, and many others. Check Settings > About > look for EID number to verify. Device must be carrier-unlocked.', 'faq', 'en', true, false, ARRAY['compatible', 'supported phones', 'device check']),
('How long does eSIM activation take?', 'QR code delivered instantly via email after purchase. Installation takes 1-2 minutes. Network connection at destination: 1-5 minutes. Tip: Install before travel, activate when you arrive.', 'faq', 'en', true, false, ARRAY['activation time', 'how long', 'instant']),
('Can I keep my phone number?', 'Yes! Use dual SIM setup - your physical SIM keeps your home number for calls/SMS, Mobile11 eSIM provides data abroad. Both work simultaneously. Set eSIM for mobile data in settings.', 'faq', 'en', true, false, ARRAY['keep number', 'dual SIM', 'phone number']),
('eSIM vs physical SIM: What''s the difference?', 'eSIM: digital, instant activation via QR code, no shipping, cannot lose, multiple profiles, newer phones only. Physical SIM: plastic card, insert in phone, shipping required, easy to lose, one per slot, works on most phones.', 'faq', 'en', true, false, ARRAY['esim vs sim', 'comparison', 'difference']),
('How do I contact Mobile11 support?', 'Live chat on website (fastest), email support@mobile11.com, LINE @mobile11. Support available 24/7 in English and Thai. Include order number for faster assistance.', 'faq', 'en', true, false, ARRAY['contact support', 'help', 'customer service']),
('Can I use eSIM in multiple countries?', 'Yes! Regional and global eSIM plans work across multiple countries. Check coverage details on each plan. Single eSIM for entire multi-country trip.', 'faq', 'en', true, false, ARRAY['multiple countries', 'regional', 'global']),
('How do I activate my eSIM?', 'After purchase, receive QR code via email. Scan with phone camera or go to Settings > Cellular > Add eSIM. Follow on-screen instructions. Takes less than 5 minutes.', 'faq', 'en', true, false, ARRAY['activate', 'install', 'QR code']),

-- FAQ from landing page (English)
('What if I need help with my eSIM?', 'Our support team is available 24/7 via chat, email, or LINE. We offer support in both English and Thai to assist you with any questions or issues.', 'faq', 'en', true, false, ARRAY['help', 'support', '24/7']);

