-- Troubleshoot articles (Thai)
INSERT INTO kb_articles (title, content, category, language, is_published, is_internal, tags) VALUES
('eSIM ของฉันไม่ทำงาน', 'ขั้นตอนการแก้ปัญหาเมื่อ eSIM ไม่ทำงาน ตรวจสอบความเข้ากันได้ของอุปกรณ์ - ตรวจสอบว่าอุปกรณ์รองรับ eSIM และปลดล็อคจากผู้ให้บริการ ตรวจสอบการเชื่อมต่ออินเทอร์เน็ต - ต้องใช้ Wi-Fi หรือข้อมูลมือถือที่เสถียร รีสตาร์ทอุปกรณ์ - ปิดเครื่อง รอ 30 วินาที เปิดใหม่ ติดต่อฝ่ายสนับสนุนหากปัญหายังคงอยู่', 'troubleshoot', 'th', true, false, ARRAY['เปิดใช้งาน', 'ไม่ทำงาน', 'แก้ปัญหา']),
('ไม่มีการเชื่อมต่ออินเทอร์เน็ต', 'จะทำอย่างไรเมื่อ eSIM ไม่มีการเชื่อมต่อข้อมูล เปิดโรมมิ่งข้อมูลในตั้งค่า > เซลลูลาร์ เลือก eSIM สำหรับข้อมูลในการตั้งค่า ตรวจสอบพื้นที่ครอบคลุมเครือข่าย ลองเลือกเครือข่ายด้วยตนเอง', 'troubleshoot', 'th', true, false, ARRAY['ไม่มีอินเทอร์เน็ต', 'เชื่อมต่อ', 'โรมมิ่ง']),
('ความเร็วอินเทอร์เน็ตช้า', 'เคล็ดลับเพื่อปรับปรุงความเร็ว eSIM ตรวจสอบขีดจำกัดข้อมูลในแดชบอร์ด ความแออัดของเครือข่ายขึ้นอยู่กับเวลาและสถานที่ เลือกประเภทเครือข่ายที่ต้องการ (5G/LTE) ในการตั้งค่า', 'troubleshoot', 'th', true, false, ARRAY['ช้า', 'ความเร็ว', 'เครือข่าย']),
('ไม่สามารถสแกน QR code ได้', 'จะทำอย่างไรถ้าไม่สามารถสแกน QR code eSIM ได้ แสดง QR บนอุปกรณ์อื่น ตรวจสอบแสงสว่าง ลองติดตั้งด้วยตนเองด้วยที่อยู่ SM-DP+ และรหัสเปิดใช้งานจากอีเมล', 'troubleshoot', 'th', true, false, ARRAY['QR code', 'สแกน', 'ติดตั้ง']),
('eSIM ค้างอยู่ที่กำลังเปิดใช้งาน', 'จะทำอย่างไรเมื่อ eSIM ค้างในสถานะกำลังเปิดใช้งาน โดยปกติใช้เวลา 1-5 นาที ตรวจสอบการเชื่อมต่ออินเทอร์เน็ต รีสตาร์ทอุปกรณ์ ตรวจสอบการตั้งค่าเซลลูลาร์ ติดต่อฝ่ายสนับสนุนหากค้างนานกว่า 30 นาที', 'troubleshoot', 'th', true, false, ARRAY['ค้าง', 'กำลังเปิดใช้งาน', 'รอ']),
('ข้อผิดพลาด "ไม่สามารถเพิ่มแผนเซลลูลาร์"', 'วิธีแก้ไขข้อผิดพลาด "ไม่สามารถเพิ่มแผนเซลลูลาร์จากผู้ให้บริการนี้" ตรวจสอบว่าอุปกรณ์ถูกล็อคกับผู้ให้บริการหรือไม่ ยืนยันว่า QR code ไม่เคยถูกใช้ อัปเดตซอฟต์แวร์ ลองติดตั้งด้วยตนเอง', 'troubleshoot', 'th', true, false, ARRAY['ข้อผิดพลาด', 'ไม่สามารถเพิ่ม', 'ล็อค']),

-- eSIM Data Plan articles (Thai)
('วิธีเติมเงิน eSIM ของคุณ', 'เรียนรู้วิธีเพิ่มข้อมูลให้กับ eSIM ที่มีอยู่ การเติมเงินช่วยเพิ่มข้อมูลโดยไม่ต้องติดตั้งใหม่ เข้าสู่ระบบบัญชี ไปที่ eSIM ของฉัน เลือก eSIM คลิกเติมเงิน ข้อมูลเพิ่มอัตโนมัติภายใน 5-15 นาที', 'esim-data-plan', 'th', true, false, ARRAY['เติมเงิน', 'เพิ่มข้อมูล', 'รีโหลด']),
('ทำความเข้าใจประเภทแพ็คเกจ Mobile11', 'เรียนรู้เกี่ยวกับแพ็คเกจ Day Pass, Max Speed และ Limitless ทุกแพ็คเกจไม่จำกัดจริง - คุณจะไม่ถูกตัดเลย Day Pass: โควต้าความเร็วสูงรายวันรีเซ็ตทุก 24 ชั่วโมง จากนั้น 1 Mbps Max Speed: ข้อมูลความเร็วสูงล่วงหน้า จากนั้น 384 Kbps Limitless: ไม่จำกัดที่ความเร็วสูงสุดไม่มีการลดความเร็ว', 'esim-data-plan', 'th', true, false, ARRAY['ประเภทแพ็คเกจ', 'day pass', 'limitless', 'ไม่จำกัด']),
('eSIM ภูมิภาค vs ท้องถิ่น', 'เปรียบเทียบตัวเลือก eSIM ภูมิภาคและท้องถิ่น eSIM ท้องถิ่น: คุ้มค่าที่สุดต่อ GB เหมาะสำหรับประเทศเดียว eSIM ภูมิภาค: eSIM เดียวสำหรับหลายประเทศ สะดวกสำหรับเดินทางหลายจุดหมาย', 'esim-data-plan', 'th', true, false, ARRAY['ภูมิภาค', 'ท้องถิ่น', 'หลายประเทศ']),
('อายุ eSIM เริ่มเมื่อไหร่?', 'อายุเริ่มเมื่อคุณเชื่อมต่อเครือข่ายครั้งแรกที่ปลายทาง ไม่ใช่เมื่อติดตั้ง ติดตั้งก่อนเดินทาง เปิดใช้งานเมื่อถึง ตรวจสอบเงื่อนไขแพ็คเกจสำหรับรายละเอียด', 'esim-data-plan', 'th', true, false, ARRAY['อายุ', 'วันเริ่ม', 'หมดอายุ']),
('วิธีตรวจสอบการใช้ข้อมูล', 'ตรวจสอบการใช้ข้อมูลในแดชบอร์ดบัญชี Mobile11 ภายใต้ eSIM ของฉัน ตรวจสอบในการตั้งค่าอุปกรณ์: iPhone ตั้งค่า > เซลลูลาร์, Android ตั้งค่า > การใช้ข้อมูล', 'esim-data-plan', 'th', true, false, ARRAY['การใช้ข้อมูล', 'ตรวจสอบยอด', 'ข้อมูลเหลือ']),

-- Payments and Billing articles (Thai)
('วิธีการชำระเงินที่รับ', 'Mobile11 รับบัตรเครดิต (Visa, Mastercard, Amex) บัตรเดบิต PayPal Google Pay Apple Pay และวิธีการชำระเงินท้องถิ่นรวมถึง PromptPay ในไทย', 'payments-billing', 'th', true, false, ARRAY['วิธีชำระเงิน', 'บัตรเครดิต', 'PayPal']),
('นโยบายการคืนเงิน', 'คืนเงินได้ภายใน 30 วันหาก eSIM ยังไม่ได้ติดตั้ง/เปิดใช้งาน เมื่อสแกน QR code แล้ว eSIM ไม่สามารถคืนเงินได้ ติดต่อฝ่ายสนับสนุนพร้อมหมายเลขคำสั่งซื้อ', 'payments-billing', 'th', true, false, ARRAY['คืนเงิน', 'ขอเงินคืน', 'นโยบาย']),
('วิธีรับใบแจ้งหนี้', 'เข้าถึงใบแจ้งหนี้ในแดชบอร์ดบัญชีภายใต้ประวัติคำสั่งซื้อ คลิกคำสั่งซื้อเพื่อดูและดาวน์โหลดใบแจ้งหนี้ PDF ติดต่อฝ่ายสนับสนุนสำหรับความต้องการเพิ่มเติม', 'payments-billing', 'th', true, false, ARRAY['ใบแจ้งหนี้', 'ใบเสร็จ', 'บิล']),
('สกุลเงินและราคา', 'ราคาแสดงเป็น USD โดยเริ่มต้น สกุลเงินสามารถเปลี่ยนเป็น THB และอื่นๆ ค่าใช้จ่ายสุดท้ายในสกุลเงินท้องถิ่นขึ้นอยู่กับอัตราแลกเปลี่ยนของผู้ออกบัตร', 'payments-billing', 'th', true, false, ARRAY['สกุลเงิน', 'ราคา', 'อัตราแลกเปลี่ยน']),
('การชำระเงินล้มเหลว', 'หากการชำระเงินล้มเหลว ตรวจสอบรายละเอียดบัตร ยอดเงินเพียงพอ ลองวิธีชำระเงินอื่น ติดต่อธนาคารหากบัตรถูกปฏิเสธ ลองอีกครั้งหรือใช้การชำระเงินทางเลือก', 'payments-billing', 'th', true, false, ARRAY['ชำระเงินล้มเหลว', 'ปฏิเสธ', 'ข้อผิดพลาด']),
('โปรโมโค้ดและส่วนลด', 'ใส่โปรโมโค้ดที่ checkout ในช่องส่วนลด โปรโมโค้ดไม่สามารถใช้ร่วมกับส่วนลดการแนะนำ แต่ละโปรโมโค้ดมีเงื่อนไขและระยะเวลาเฉพาะ', 'payments-billing', 'th', true, false, ARRAY['โปรโมโค้ด', 'ส่วนลด', 'คูปอง']),

-- Account articles (Thai)
('วิธีสร้างบัญชี', 'สร้างบัญชีบนเว็บไซต์หรือแอป Mobile11 ใส่อีเมลและรหัสผ่าน หรือลงทะเบียนด้วย Google/LINE ยืนยันอีเมลเพื่อเสร็จสิ้นการลงทะเบียน ต้องมีบัญชีสำหรับโปรแกรมสะสมคะแนนและจัดการคำสั่งซื้อ', 'account', 'th', true, false, ARRAY['สร้างบัญชี', 'ลงทะเบียน', 'สมัคร']),
('ลืมรหัสผ่าน', 'รีเซ็ตรหัสผ่านผ่านหน้าเข้าสู่ระบบ คลิก "ลืมรหัสผ่าน" ใส่อีเมล ตรวจสอบกล่องจดหมายสำหรับลิงก์รีเซ็ต ลิงก์ใช้ได้ 24 ชั่วโมง ติดต่อฝ่ายสนับสนุนหากมีปัญหา', 'account', 'th', true, false, ARRAY['ลืมรหัสผ่าน', 'รีเซ็ต', 'เข้าสู่ระบบ']),
('Mobile11 Money คืออะไร?', 'Mobile11 Money คือสกุลเงินรางวัลเงินคืนของเรา รับ 5-15% คืนตามระดับสมาชิก ใช้ที่ checkout เพื่อลดยอดรวม 1 Mobile11 Money = $1 USD มีอายุ 1 ปี (รีเซ็ตทุกการซื้อ)', 'account', 'th', true, false, ARRAY['mobile11 money', 'เงินคืน', 'รางวัล']),
('โปรแกรมสะสมคะแนน Mobile11', 'โปรแกรมสะสมคะแนน 3 ระดับ: Explorer (เงินคืน 5%), Silver Explorer (10% ที่ $100), Gold Explorer (15% ที่ $500) ลงทะเบียนอัตโนมัติเมื่อซื้อครั้งแรก ระดับไม่หมดอายุ', 'account', 'th', true, false, ARRAY['สะสมคะแนน', 'ระดับ', 'เงินคืน', 'รางวัล']),
('วิธีใช้ Mobile11 Money', 'ใช้ Mobile11 Money ที่ checkout ใส่จำนวนที่ต้องการใช้หรือคลิก "ใช้ทั้งหมด" ยอดเหลือแสดงในบัญชี สามารถรวมกับการชำระเงินปกติแต่ไม่สามารถใช้กับโปรโมโค้ด', 'account', 'th', true, false, ARRAY['ใช้รางวัล', 'แลก', 'checkout']),
('โปรแกรมแนะนำเพื่อน', 'แนะนำเพื่อนและรับ $5.00 Mobile11 Money เมื่อพวกเขาสั่งซื้อครั้งแรก (ขั้นต่ำ $10) แชร์ลิงก์แนะนำของคุณจากแดชบอร์ดบัญชี เพื่อนได้รับส่วนลดต้อนรับ $5.00 ด้วย', 'account', 'th', true, false, ARRAY['แนะนำเพื่อน', 'เชิญเพื่อน', 'รับรางวัล']),
('ดูประวัติคำสั่งซื้อ', 'เข้าถึงประวัติคำสั่งซื้อในแดชบอร์ดบัญชี ดูคำสั่งซื้อที่ผ่านมา ดาวน์โหลด QR code eSIM ตรวจสอบสถานะคำสั่งซื้อ และเข้าถึงใบแจ้งหนี้', 'account', 'th', true, false, ARRAY['ประวัติ', 'คำสั่งซื้อ', 'การซื้อ']),

-- FAQ articles (Thai)
('eSIM คืออะไร?', 'eSIM (embedded SIM) คือ SIM ดิจิทัลที่ช่วยให้คุณเปิดใช้งานแผนเซลลูลาร์โดยไม่ต้องใช้ SIM การ์ดจริง มันถูกสร้างในอุปกรณ์และสามารถโปรแกรมด้วยข้อมูลผู้ให้บริการทางไกล ประโยชน์หลัก: เปิดใช้งานทันที ไม่มี SIM จริงให้หาย เก็บหลายโปรไฟล์ได้ เป็นมิตรกับสิ่งแวดล้อม', 'faq', 'th', true, false, ARRAY['eSIM คืออะไร', 'ความหมาย', 'SIM ดิจิทัล']),
('โทรศัพท์ของฉันรองรับ eSIM ไหม?', 'สมาร์ทโฟนรุ่นใหม่ส่วนใหญ่รองรับ eSIM iPhone ที่รองรับ: XS, XR และใหม่กว่า, SE รุ่นที่ 2 และใหม่กว่า Android ที่รองรับ: Samsung Galaxy S20+, Google Pixel 3+ และอื่นๆ ตรวจสอบ ตั้งค่า > เกี่ยวกับ > มองหาหมายเลข EID เพื่อยืนยัน อุปกรณ์ต้องปลดล็อคจากผู้ให้บริการ', 'faq', 'th', true, false, ARRAY['รองรับ', 'โทรศัพท์ที่รองรับ', 'ตรวจสอบอุปกรณ์']),
('การเปิดใช้งาน eSIM ใช้เวลานานแค่ไหน?', 'QR code ส่งทันทีทางอีเมลหลังซื้อ การติดตั้งใช้เวลา 1-2 นาที การเชื่อมต่อเครือข่ายที่ปลายทาง: 1-5 นาที เคล็ดลับ: ติดตั้งก่อนเดินทาง เปิดใช้งานเมื่อถึง', 'faq', 'th', true, false, ARRAY['เวลาเปิดใช้งาน', 'นานแค่ไหน', 'ทันที']),
('ฉันสามารถใช้หมายเลขโทรศัพท์เดิมได้ไหม?', 'ได้! ใช้ dual SIM - SIM จริงเก็บหมายเลขบ้านสำหรับโทร/SMS, Mobile11 eSIM ให้ข้อมูลในต่างประเทศ ทั้งสองทำงานพร้อมกัน ตั้ง eSIM สำหรับข้อมูลมือถือในการตั้งค่า', 'faq', 'th', true, false, ARRAY['เก็บหมายเลข', 'dual SIM', 'หมายเลขโทรศัพท์']),
('eSIM vs SIM จริง: ต่างกันอย่างไร?', 'eSIM: ดิจิทัล เปิดใช้งานทันทีผ่าน QR code ไม่ต้องส่ง หายไม่ได้ หลายโปรไฟล์ เฉพาะโทรศัพท์ใหม่ SIM จริง: การ์ดพลาสติก ใส่ในโทรศัพท์ ต้องส่ง หายง่าย หนึ่งต่อช่อง ใช้ได้กับโทรศัพท์ส่วนใหญ่', 'faq', 'th', true, false, ARRAY['esim vs sim', 'เปรียบเทียบ', 'ต่างกัน']),
('ฉันจะติดต่อฝ่ายสนับสนุน Mobile11 ได้อย่างไร?', 'แชทสดบนเว็บไซต์ (เร็วที่สุด) อีเมล support@mobile11.com LINE @mobile11 ฝ่ายสนับสนุนพร้อมให้บริการ 24/7 ภาษาไทยและอังกฤษ แนบหมายเลขคำสั่งซื้อเพื่อรับความช่วยเหลือเร็วขึ้น', 'faq', 'th', true, false, ARRAY['ติดต่อฝ่ายสนับสนุน', 'ช่วยเหลือ', 'บริการลูกค้า']),
('ฉันสามารถใช้ eSIM ในหลายประเทศได้ไหม?', 'ได้! แพ็คเกจ eSIM ภูมิภาคและทั่วโลกใช้งานได้ในหลายประเทศ ตรวจสอบรายละเอียดความครอบคลุมในแต่ละแพ็คเกจ eSIM เดียวสำหรับการเดินทางหลายประเทศ', 'faq', 'th', true, false, ARRAY['หลายประเทศ', 'ภูมิภาค', 'ทั่วโลก']),
('ฉันเปิดใช้งาน eSIM อย่างไร?', 'หลังซื้อ รับ QR code ทางอีเมล สแกนด้วยกล้องโทรศัพท์หรือไปที่ ตั้งค่า > เซลลูลาร์ > เพิ่ม eSIM ทำตามคำแนะนำบนหน้าจอ ใช้เวลาไม่ถึง 5 นาที', 'faq', 'th', true, false, ARRAY['เปิดใช้งาน', 'ติดตั้ง', 'QR code']),
('ถ้าฉันต้องการความช่วยเหลือเกี่ยวกับ eSIM?', 'ทีมสนับสนุนของเราพร้อมให้บริการ 24/7 ผ่านแชท อีเมล หรือ LINE เราให้บริการทั้งภาษาไทยและอังกฤษเพื่อช่วยเหลือคุณกับทุกคำถามหรือปัญหา', 'faq', 'th', true, false, ARRAY['ช่วยเหลือ', 'สนับสนุน', '24/7']);